import { useState, useEffect, useCallback } from "react";
import "./index.css";

const GEMINI_MODEL = "gemini-2.0-flash";

const CATEGORIES = ["Work", "Study", "Personal", "Health", "Finance", "Other"];
const PRIORITIES = ["critical", "high", "medium", "low"];

function getPriorityScore(task) {
  const now = new Date();
  const deadline = new Date(task.deadline);
  const hoursLeft = (deadline - now) / 36e5;
  const pMap = { critical: 4, high: 3, medium: 2, low: 1 };
  return pMap[task.priority] * 10 - Math.max(0, hoursLeft) * 0.1;
}

function formatDeadline(dt) {
  if (!dt) return "";
  const d = new Date(dt);
  const now = new Date();
  const diff = d - now;
  if (diff < 0) return "Overdue!";
  const h = Math.floor(diff / 36e5);
  if (h < 1) return "< 1 hour";
  if (h < 24) return `${h}h left`;
  const days = Math.floor(h / 24);
  if (days === 1) return "Tomorrow";
  return `${days} days left`;
}

function isOverdue(dt) {
  return dt && new Date(dt) < new Date();
}

const SAMPLE_TASKS = [
  { id: 1, title: "Submit internship report", category: "Study", priority: "critical", deadline: new Date(Date.now() + 3600000 * 5).toISOString(), notes: "Include CNN model results", done: false, steps: [] },
  { id: 2, title: "Complete DSA assignment", category: "Study", priority: "high", deadline: new Date(Date.now() + 3600000 * 26).toISOString(), notes: "", done: false, steps: [] },
  { id: 3, title: "Register for placement portal", category: "Work", priority: "medium", deadline: new Date(Date.now() + 3600000 * 72).toISOString(), notes: "", done: false, steps: [] },
];

export default function App() {
  const [page, setPage] = useState("dashboard");
  const [tasks, setTasks] = useState(SAMPLE_TASKS);
  const [apiKey, setApiKey] = useState("");
  const [apiKeyInput, setApiKeyInput] = useState("");
  const [showKeyInput, setShowKeyInput] = useState(false);
  const [aiMessage, setAiMessage] = useState("");
  const [aiLoading, setAiLoading] = useState(false);
  const [schedule, setSchedule] = useState([]);
  const [newTask, setNewTask] = useState({ title: "", category: "Study", priority: "medium", deadline: "", notes: "" });
  const [activeTab, setActiveTab] = useState("all");
  const [draftMessage, setDraftMessage] = useState("");

  const callGemini = useCallback(async (prompt) => {
    if (!apiKey) return null;
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${apiKey}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] }),
      }
    );
    const data = await res.json();
    if (data.error) throw new Error(data.error.message);
    return data.candidates?.[0]?.content?.parts?.[0]?.text || "";
  }, [apiKey]);

  const pending = tasks.filter(t => !t.done);
  const done = tasks.filter(t => t.done);
  const overdue = tasks.filter(t => !t.done && isOverdue(t.deadline));
  const sorted = [...pending].sort((a, b) => getPriorityScore(b) - getPriorityScore(a));

  async function analyzeDay() {
    if (!apiKey) { setShowKeyInput(true); return; }
    setAiLoading(true);
    setAiMessage("");
    try {
      const taskSummary = sorted.slice(0, 6).map(t =>
        `- "${t.title}" [${t.priority}] due: ${t.deadline ? new Date(t.deadline).toLocaleString() : "no deadline"} (${t.category})`
      ).join("\n");
      const prompt = `You are TaskMind, an AI productivity companion for a college student at NIT Warangal.
Current time: ${new Date().toLocaleString()}
Pending tasks:
${taskSummary}

Give a concise, friendly day analysis (3-4 sentences max). Tell them:
1. What to focus on RIGHT NOW and why
2. One warning about overdue or near-deadline tasks
3. One motivating tip
Be direct, warm, and student-friendly. No bullet points, just natural sentences.`;
      const reply = await callGemini(prompt);
      setAiMessage(reply);
    } catch (e) {
      setAiMessage("Could not connect to Gemini. Check your API key.");
    }
    setAiLoading(false);
  }

  async function breakdownTask(task) {
    if (!apiKey) { setShowKeyInput(true); return; }
    setAiLoading(true);
    try {
      const prompt = `You are TaskMind. Break down this task into 4-5 clear, actionable steps for a college student.
Task: "${task.title}"
Category: ${task.category}
Priority: ${task.priority}
Deadline: ${task.deadline ? new Date(task.deadline).toLocaleString() : "flexible"}
Notes: ${task.notes || "none"}

Return ONLY a JSON array of steps like: ["Step 1 description", "Step 2 description", ...]
No other text, just valid JSON array.`;
      const reply = await callGemini(prompt);
      const clean = reply.replace(/```json|```/g, "").trim();
      const steps = JSON.parse(clean);
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, steps } : t));
    } catch (e) {
      console.error(e);
    }
    setAiLoading(false);
  }

  async function generateSchedule() {
    if (!apiKey) { setShowKeyInput(true); return; }
    setAiLoading(true);
    setSchedule([]);
    try {
      const taskSummary = sorted.slice(0, 5).map(t =>
        `"${t.title}" [${t.priority}] due ${t.deadline ? new Date(t.deadline).toLocaleString() : "flexible"}`
      ).join(", ");
      const prompt = `You are TaskMind. Create a smart schedule for today for a student.
Current time: ${new Date().toLocaleTimeString()}
Tasks: ${taskSummary}

Return ONLY a JSON array of schedule blocks:
[{"time":"9:00 AM","task":"task name","duration":"45 min","tip":"short tip"}]
Max 5 blocks. Order by priority and deadline urgency. No other text, just valid JSON.`;
      const reply = await callGemini(prompt);
      const clean = reply.replace(/```json|```/g, "").trim();
      const blocks = JSON.parse(clean);
      setSchedule(blocks);
    } catch (e) {
      setSchedule([]);
    }
    setAiLoading(false);
  }

  async function draftExtensionEmail(task) {
    if (!apiKey) { setShowKeyInput(true); return; }
    setAiLoading(true);
    setDraftMessage("");
    try {
      const prompt = `Write a short, polite email from a BTech student at NIT Warangal requesting a deadline extension for: "${task.title}".
Current deadline: ${task.deadline ? new Date(task.deadline).toLocaleString() : "soon"}.
Keep it professional, 3-4 sentences. Include subject line. Student name: Pernapati Tarun Eswar.`;
      const reply = await callGemini(prompt);
      setDraftMessage(reply);
      setPage("drafts");
    } catch (e) {
      setDraftMessage("Could not generate draft. Please check your API key.");
    }
    setAiLoading(false);
  }

  function addTask() {
    if (!newTask.title.trim()) return;
    setTasks(prev => [...prev, { ...newTask, id: Date.now(), done: false, steps: [] }]);
    setNewTask({ title: "", category: "Study", priority: "medium", deadline: "", notes: "" });
  }

  function toggleTask(id) {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, done: !t.done } : t));
  }

  function deleteTask(id) {
    setTasks(prev => prev.filter(t => t.id !== id));
  }

  const filteredTasks = tasks.filter(t => {
    if (activeTab === "all") return !t.done;
    if (activeTab === "done") return t.done;
    if (activeTab === "overdue") return !t.done && isOverdue(t.deadline);
    return !t.done && t.category === activeTab;
  });

  return (
    <div className="app">
      <aside className="sidebar">
        <div className="logo">
          <div className="logo-icon">T</div>
          <span className="logo-text">TaskMind</span>
        </div>
        {[
          { id: "dashboard", icon: "⊞", label: "Dashboard" },
          { id: "tasks", icon: "✓", label: "My Tasks" },
          { id: "schedule", icon: "◷", label: "AI Schedule" },
          { id: "drafts", icon: "✉", label: "AI Drafts" },
          { id: "settings", icon: "⚙", label: "Settings" },
        ].map(n => (
          <button key={n.id} className={`nav-item ${page === n.id ? "active" : ""}`} onClick={() => setPage(n.id)}>
            <span>{n.icon}</span> {n.label}
          </button>
        ))}
        <div style={{ flex: 1 }} />
        <div style={{ padding: "12px", background: "#f8f7ff", borderRadius: "8px", fontSize: "12px", color: "#6b7280" }}>
          <div style={{ fontWeight: 600, color: "#1a1a2e", marginBottom: 4 }}>Tarun Eswar</div>
          <div>NIT Warangal · CSE</div>
          <div style={{ marginTop: 6, display: "flex", gap: 8 }}>
            <span className="badge badge-purple">{pending.length} pending</span>
          </div>
        </div>
      </aside>

      <main className="main">
        {!apiKey && (
          <div className="api-key-banner">
            <span>⚠</span>
            <span>Add your Gemini API key to unlock AI features.</span>
            <button className="btn btn-sm btn-outline" style={{ marginLeft: "auto" }} onClick={() => setPage("settings")}>Add key</button>
          </div>
        )}

        {page === "dashboard" && (
          <Dashboard
            tasks={tasks} pending={pending} done={done} overdue={overdue} sorted={sorted}
            aiMessage={aiMessage} aiLoading={aiLoading}
            onAnalyze={analyzeDay} onBreakdown={breakdownTask} onDraft={draftExtensionEmail}
            onToggle={toggleTask}
          />
        )}

        {page === "tasks" && (
          <TasksPage
            tasks={filteredTasks} allTasks={tasks}
            newTask={newTask} setNewTask={setNewTask}
            onAdd={addTask} onToggle={toggleTask} onDelete={deleteTask}
            onBreakdown={breakdownTask} onDraft={draftExtensionEmail}
            activeTab={activeTab} setActiveTab={setActiveTab}
            aiLoading={aiLoading}
          />
        )}

        {page === "schedule" && (
          <SchedulePage schedule={schedule} onGenerate={generateSchedule} aiLoading={aiLoading} tasks={sorted} />
        )}

        {page === "drafts" && (
          <DraftsPage draft={draftMessage} aiLoading={aiLoading} tasks={pending} onDraft={draftExtensionEmail} />
        )}

        {page === "settings" && (
          <SettingsPage
            apiKey={apiKey} apiKeyInput={apiKeyInput}
            setApiKeyInput={setApiKeyInput}
            onSave={() => { setApiKey(apiKeyInput); setShowKeyInput(false); }}
          />
        )}
      </main>
    </div>
  );
}

function Dashboard({ tasks, pending, done, overdue, sorted, aiMessage, aiLoading, onAnalyze, onBreakdown, onDraft, onToggle }) {
  const urgent = sorted.filter(t => {
    const h = t.deadline ? (new Date(t.deadline) - new Date()) / 36e5 : 999;
    return h < 24 && h > 0;
  });

  return (
    <>
      <div className="page-header">
        <div className="page-title">Good {new Date().getHours() < 12 ? "morning" : new Date().getHours() < 17 ? "afternoon" : "evening"}, Tarun!</div>
        <div className="page-sub">{new Date().toLocaleDateString("en-IN", { weekday: "long", year: "numeric", month: "long", day: "numeric" })}</div>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-label">Pending tasks</div>
          <div className="stat-value">{pending.length}</div>
          <div className="stat-sub">to complete</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Completed</div>
          <div className="stat-value" style={{ color: "#16a34a" }}>{done.length}</div>
          <div className="stat-sub">great work!</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Overdue</div>
          <div className="stat-value" style={{ color: overdue.length > 0 ? "#dc2626" : "#16a34a" }}>{overdue.length}</div>
          <div className="stat-sub">{overdue.length > 0 ? "needs attention" : "all clear"}</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Due today</div>
          <div className="stat-value" style={{ color: urgent.length > 0 ? "#d97706" : "#1a1a2e" }}>{urgent.length}</div>
          <div className="stat-sub">within 24 hours</div>
        </div>
      </div>

      <div className="ai-panel">
        <div className="ai-header">
          <div className="ai-avatar">AI</div>
          <div>
            <div className="ai-title">TaskMind AI</div>
            <div className="ai-sub">Your productivity companion</div>
          </div>
          <button className="btn btn-primary btn-sm" style={{ marginLeft: "auto" }} onClick={onAnalyze}>
            {aiLoading ? "Thinking..." : "Analyze my day"}
          </button>
        </div>
        {aiLoading && <div className="loading-dots"><span/><span/><span/></div>}
        {aiMessage && !aiLoading && <div className="ai-message">{aiMessage}</div>}
        {!aiMessage && !aiLoading && (
          <div className="ai-message" style={{ color: "#6b7280" }}>
            Click "Analyze my day" and I'll tell you exactly what to focus on right now, based on your deadlines and priorities.
          </div>
        )}
      </div>

      <div className="card">
        <div className="card-title">Priority queue</div>
        {sorted.length === 0 && <div className="empty-state"><div className="empty-text">No pending tasks</div></div>}
        <div className="task-list">
          {sorted.slice(0, 5).map(task => (
            <TaskRow key={task.id} task={task} onToggle={onToggle} onBreakdown={onBreakdown} onDraft={onDraft} />
          ))}
        </div>
      </div>
    </>
  );
}

function TaskRow({ task, onToggle, onDelete, onBreakdown, onDraft }) {
  const [expanded, setExpanded] = useState(false);
  const over = isOverdue(task.deadline);

  return (
    <div className={`task-item ${task.done ? "done" : ""}`}>
      <div className={`task-check ${task.done ? "checked" : ""}`} onClick={() => onToggle(task.id)}>
        {task.done && <span style={{ fontSize: 10 }}>✓</span>}
      </div>
      <div className="task-content">
        <div className="task-title">{task.title}</div>
        <div className="task-meta">
          <span className={`badge badge-${task.priority === "critical" ? "critical" : task.priority === "high" ? "high" : task.priority === "medium" ? "medium" : "low"}`}>
            {task.priority}
          </span>
          <span className="badge badge-gray">{task.category}</span>
          {task.deadline && (
            <span style={{ fontSize: 11, color: over ? "#dc2626" : "#6b7280", fontWeight: over ? 600 : 400 }}>
              {over ? "⚠ " : "◷ "}{formatDeadline(task.deadline)}
            </span>
          )}
        </div>
        {task.steps && task.steps.length > 0 && expanded && (
          <div className="steps-list">
            {task.steps.map((s, i) => (
              <div key={i} className="step-item">
                <div className="step-num">{i + 1}</div>
                <span>{s}</span>
              </div>
            ))}
          </div>
        )}
        {!task.done && (
          <div style={{ display: "flex", gap: 6, marginTop: 8, flexWrap: "wrap" }}>
            <button className="ai-action-btn" onClick={() => { onBreakdown(task); setExpanded(true); }}>
              Break it down
            </button>
            {task.steps?.length > 0 && (
              <button className="ai-action-btn" onClick={() => setExpanded(e => !e)}>
                {expanded ? "Hide steps" : "Show steps"}
              </button>
            )}
            {over && onDraft && (
              <button className="ai-action-btn" style={{ color: "#dc2626", borderColor: "#fca5a5" }} onClick={() => onDraft(task)}>
                Draft extension email
              </button>
            )}
          </div>
        )}
      </div>
      {onDelete && (
        <button className="delete-btn" onClick={() => onDelete(task.id)} aria-label="Delete task">✕</button>
      )}
    </div>
  );
}

function TasksPage({ tasks, allTasks, newTask, setNewTask, onAdd, onToggle, onDelete, onBreakdown, onDraft, activeTab, setActiveTab, aiLoading }) {
  const cats = ["all", "overdue", "done", ...CATEGORIES];

  return (
    <>
      <div className="page-header">
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div className="page-title">My tasks</div>
            <div className="page-sub">{allTasks.filter(t => !t.done).length} pending · {allTasks.filter(t => t.done).length} completed</div>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-title">Add new task</div>
        <div className="form-grid" style={{ marginBottom: 12 }}>
          <div className="form-group" style={{ gridColumn: "1 / -1" }}>
            <label className="form-label">Task title</label>
            <input type="text" placeholder="What do you need to do?" value={newTask.title}
              onChange={e => setNewTask(p => ({ ...p, title: e.target.value }))}
              onKeyDown={e => e.key === "Enter" && onAdd()} />
          </div>
          <div className="form-group">
            <label className="form-label">Category</label>
            <select value={newTask.category} onChange={e => setNewTask(p => ({ ...p, category: e.target.value }))}>
              {CATEGORIES.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Priority</label>
            <select value={newTask.priority} onChange={e => setNewTask(p => ({ ...p, priority: e.target.value }))}>
              {PRIORITIES.map(p => <option key={p}>{p}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Deadline</label>
            <input type="datetime-local" value={newTask.deadline}
              onChange={e => setNewTask(p => ({ ...p, deadline: e.target.value }))} />
          </div>
          <div className="form-group">
            <label className="form-label">Notes (optional)</label>
            <input type="text" placeholder="Any details..." value={newTask.notes}
              onChange={e => setNewTask(p => ({ ...p, notes: e.target.value }))} />
          </div>
        </div>
        <button className="btn btn-primary" onClick={onAdd}>+ Add task</button>
      </div>

      <div className="tabs" style={{ overflowX: "auto" }}>
        {cats.map(c => (
          <button key={c} className={`tab ${activeTab === c ? "active" : ""}`} onClick={() => setActiveTab(c)}>
            {c.charAt(0).toUpperCase() + c.slice(1)}
          </button>
        ))}
      </div>

      {tasks.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">✓</div>
          <div className="empty-text">No tasks here</div>
          <div className="empty-sub">Add a task above to get started</div>
        </div>
      ) : (
        <div className="task-list">
          {tasks.map(task => (
            <TaskRow key={task.id} task={task} onToggle={onToggle} onDelete={onDelete} onBreakdown={onBreakdown} onDraft={onDraft} />
          ))}
        </div>
      )}
    </>
  );
}

