function DraftsPage({ draft, aiLoading, tasks, onDraft }) {
  const [copied, setCopied] = useState(false);

  function copy() {
    navigator.clipboard.writeText(draft);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  return (
    <>
      <div className="page-header">
        <div className="page-title">AI drafts</div>
        <div className="page-sub">Auto-generated emails and messages for deadline extensions</div>
      </div>

      <div className="card">
        <div className="card-title">Quick draft — deadline extension</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {tasks.slice(0, 4).map(t => (
            <button key={t.id} className="btn btn-outline" style={{ justifyContent: "flex-start" }} onClick={() => onDraft(t)}>
              ✉ Draft for: {t.title}
            </button>
          ))}
        </div>
      </div>

      {aiLoading && (
        <div className="ai-panel">
          <div className="loading-dots"><span/><span/><span/></div>
        </div>
      )}

      {draft && !aiLoading && (
        <div className="card">
          <div className="card-title" style={{ justifyContent: "space-between" }}>
            <span>Generated draft</span>
            <button className="btn btn-sm btn-outline" onClick={copy}>{copied ? "Copied!" : "Copy"}</button>
          </div>
          <div style={{ background: "#f8f7ff", borderRadius: 8, padding: 16, fontSize: 14, lineHeight: 1.7, whiteSpace: "pre-line", color: "#1a1a2e" }}>
            {draft}
          </div>
        </div>
      )}

      {!draft && !aiLoading && (
        <div className="empty-state">
          <div className="empty-icon">✉</div>
          <div className="empty-text">No drafts yet</div>
          <div className="empty-sub">Select a task above to generate an extension request email</div>
        </div>
      )}
    </>
  );
}

